type%heft nat = | Zero | Suc of nat
let%heft_primrec plus (m : nat) = match (m:nat) with | Zero -> fun (n:nat) -> (n:nat) | Suc (m':nat) -> fun (n:nat) -> Suc (plus (m':nat) (n:nat))
let%heft_goal plus_zero_right = forall (fun (m:nat) -> plus (m:nat) zero = (m:nat) )

